// =============================================================================
// Game Simulation Loop
//
// Requires env var:  OPENROUTER_API_KEY
// Optional env var:  EVAL_MODEL  (default: google/gemini-2.5-flash-preview)
//
// context  = narrative describing the user + the character they are thinking of
// thoughts = user's internal motivation / mindset (NOT character Y/N facts)
// =============================================================================

const trigger = $('Execute Workflow Trigger').item.json;
const fileData = $input.item.json;

// Decode base64 system prompt (GitHub API returns content in base64)
const cleanB64 = (fileData.content || '').replace(/\n/g, '');
const systemPrompt = Buffer.from(cleanB64, 'base64').toString('utf8');

const chatMessage = trigger.chatMessage;
const context = trigger.context;
const thoughts = trigger.thoughts;
const maxIter = trigger.max_iterations || 40;
const model = $env.EVAL_MODEL || 'google/gemini-2.5-flash-preview';
const apiKey = $env.OPENROUTER_API_KEY;

if (!apiKey) throw new Error('OPENROUTER_API_KEY is not set in n8n environment variables (Settings > Variables)');

const BASE_URL = 'https://openrouter.ai/api/v1/chat/completions';

// LLM call helper
const callLLM = async (messages, sysOverride) => {
  const payload = {
    model: model,
    temperature: 0.1,
    messages: sysOverride
      ? [{ role: 'system', content: sysOverride }].concat(messages)
      : messages
  };
  const res = await this.helpers.httpRequest({
    method: 'POST',
    url: BASE_URL,
    headers: {
      'Authorization': 'Bearer ' + apiKey,
      'Content-Type': 'application/json'
    },
    body: JSON.stringify(payload)
  });
  return {
    text: res.choices[0].message.content.trim(),
    tokens: (res.usage || {}).total_tokens || 0
  };
};

// User simulator system prompt.
// context contains the character name and the user scenario; thoughts is the user motivation.
// The simulator uses the LLM's own knowledge of the character to answer guessing questions.
const USER_SIM = [
  'You are roleplaying as a user in a guessing game. Your scenario: ' + context + '.',
  'Your mindset going into the game: ' + thoughts,
  '',
  'Rules:',
  '- Answer every question from the host with ONLY one of: Yes / No / Unknown / Probably / Probably not',
  '- Use your knowledge of the character described in your scenario to answer accurately',
  '- If the host makes a direct guess naming a character, reply Yes only if that is the character in your scenario, otherwise No',
  '- Never reveal the character name or any identifying detail unprompted — only confirm or deny explicit guesses'
].join('\n');

// Conversation history for the agent
const history = [
  { role: 'system', content: systemPrompt },
  { role: 'user', content: chatMessage }
];

let iterations = 0;
let success = false;
let totalTokens = 0;

while (iterations < maxIter) {
  // --- Agent turn ---
  const akResp = await callLLM(history);
  totalTokens += akResp.tokens;
  history.push({ role: 'assistant', content: akResp.text });
  iterations++;

  // Detect if the agent is making a guess
  const isGuess = /is your character|are you thinking of|i think it.s|i believe it.*is|my answer is|i have reached/i.test(akResp.text);

  // --- Simulated user turn ---
  const userResp = await callLLM(
    [{ role: 'user', content: akResp.text }],
    USER_SIM
  );
  totalTokens += userResp.tokens;
  history.push({ role: 'user', content: userResp.text });

  // Check for successful guess
  if (isGuess && userResp.text.trim().toLowerCase().startsWith('yes')) {
    success = true;
    break;
  }
}

return [{ json: {
  iterations: iterations,
  success: success,
  model: model,
  tokens_used: totalTokens
}}];
